## Comunicación Avanzada

### Event Bus

Para comunicación entre Web Components que no tienen relación padre-hijo:

```typescript
// shared/services/event-bus.service.ts
import { Injectable } from '@angular/core';
import { Subject, Observable } from 'rxjs';
import { filter, map } from 'rxjs/operators';

interface AppEvent {
  type: string;
  payload: any;
}

@Injectable({ providedIn: 'root' })
export class EventBusService {
  private eventSubject = new Subject<AppEvent>();

  // Emitir evento
  emit(type: string, payload: any) {
    this.eventSubject.next({ type, payload });
  }

  // Escuchar eventos
  on(eventType: string): Observable<any> {
    return this.eventSubject.pipe(
      filter(event => event.type === eventType),
      map(event => event.payload)
    );
  }
}
```

Uso en componentes:

```typescript
// Emitir desde un Web Component
export class CitationHubWrapperComponent {
  constructor(private eventBus: EventBusService) {}

  onAppointmentBooked(event: CustomEvent) {
    this.eventBus.emit('appointment:booked', event.detail);
  }
}

// Escuchar en otro componente
export class DashboardComponent implements OnInit {
  constructor(private eventBus: EventBusService) {}

  ngOnInit() {
    this.eventBus.on('appointment:booked').subscribe((data) => {
      console.log('Nueva cita desde otro componente:', data);
      this.refreshAppointments();
    });
  }
}
```

