# CI/CD y Deployment

## Pipeline de Jenkins

Asyb-Portal utiliza **Jenkins** para automatizar el proceso de build y deploy.

### Jenkinsfile

```groovy
// Jenkinsfile
pipeline {
  agent any

  parameters {
    choice(name: 'ENVIRONMENT', choices: ['dev', 'pre', 'pro'], description: 'Target environment')
    choice(name: 'PLATFORM', choices: ['web', 'android', 'ios'], description: 'Platform to build')
  }

  environment {
    NODE_VERSION = '16.x'
    ANDROID_HOME = '/usr/local/android-sdk'
  }

  stages {
    stage('Checkout') {
      steps {
        checkout scm
      }
    }

    stage('Install Dependencies') {
      steps {
        sh 'npm ci'
      }
    }

    stage('Lint') {
      steps {
        sh 'npm run lint'
      }
    }

    stage('Test') {
      steps {
        sh 'npm run test -- --watch=false --browsers=ChromeHeadless'
      }
    }

    stage('Build') {
      steps {
        script {
          if (params.PLATFORM == 'web') {
            sh "npm run build:${params.ENVIRONMENT}"
          } else if (params.PLATFORM == 'android') {
            sh "npm run build:${params.ENVIRONMENT}"
            sh 'npx cap sync android'
            sh 'cd android && ./gradlew assembleRelease'
          } else if (params.PLATFORM == 'ios') {
            sh "npm run build:${params.ENVIRONMENT}"
            sh 'npx cap sync ios'
            // iOS build se hace manual en Xcode
          }
        }
      }
    }

    stage('Deploy') {
      when {
        expression { params.PLATFORM == 'web' }
      }
      steps {
        script {
          if (params.ENVIRONMENT == 'pro') {
            sh 'npm run deploy:prod'
          } else if (params.ENVIRONMENT == 'pre') {
            sh 'npm run deploy:pre'
          }
        }
      }
    }
  }

  post {
    success {
      echo 'Build successful!'
      // Notificar en Slack
    }
    failure {
      echo 'Build failed!'
      // Notificar en Slack
    }
  }
}
```

